 _dp_log_error() { echo "${_DP_RED}[dispatch]${_DP_NC} $*" >&2; }
-_dp_log_debug() { [[ "${DISPATCH_DEBUG:-}" == "1" ]] && echo "${_DP_BLUE}[dispatch:debug]${_DP_NC} $*" >&2; }
+_dp_log_debug() { [[ "${DISPATCH_DEBUG:-}" == "1" ]] && echo "${_DP_BLUE}[dispatch:debug]${_DP_NC} $*" >&2 || true; }

